#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long X,Y; scanf("%lld %lld",&X,&Y);
        long long num = 10LL * (Y - X);
        long long den = 100 - Y;
        long long ans = (num + den - 1) / den; // ceiling division
        printf("%lld\n", ans);
    }
    return 0;
}

